/**
 * KRN-14 — gable roof for a dormer. The ridge runs along the dormer's
 * longer plan axis at `ridgeHeightM` above the eave. Two sloped faces meet
 * at the ridge. Returned mesh is centred at (0, eaveY, 0) — the caller
 * positions it.
 */
export function buildGableDormerRoof(
  widthM: number,
  depthM: number,
  roofThickM: number,
  ridgeHeightM: number,
  ridgeAlongX: boolean,
  material: THREE.Material,
): THREE.Mesh {
  // Width runs along the host ridge axis; depth runs across.
  // Determine which world axis is the dormer's *long* axis.
  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
  // Half extents in world coords (X, Z) regardless of ridge orientation.
  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
  const eaveY = roofThickM; // sit on top of roofThickM eave plate
  const ridgeY = eaveY + ridgeHeightM;

  // Vertices: 4 eave corners + 2 ridge endpoints.
  const positions: number[] = [];
  const indices: number[] = [];
  if (longAlongWorldX) {
    // Ridge along world-X: spans (-hxWorld..+hxWorld, ridgeY, 0)
    // eaves at z = ±hzWorld, y = eaveY
    // Vertices: 0..3 eave (corners), 4..5 ridge ends
    positions.push(-hxWorld, eaveY, -hzWorld); // 0: front-left eave
    positions.push(hxWorld, eaveY, -hzWorld); //  1: front-right eave
    positions.push(hxWorld, eaveY, hzWorld); //   2: back-right eave
    positions.push(-hxWorld, eaveY, hzWorld); //  3: back-left eave
    positions.push(-hxWorld, ridgeY, 0); //       4: ridge -X end
    positions.push(hxWorld, ridgeY, 0); //        5: ridge +X end
    // Two sloped faces:
    indices.push(0, 1, 5, 0, 5, 4); // front slope (-Z side)
    indices.push(2, 3, 4, 2, 4, 5); // back slope (+Z side)
    // Two triangular gable ends:
    indices.push(0, 4, 3); // -X end
    indices.push(1, 2, 5); // +X end
  } else {
    // Ridge along world-Z
    positions.push(-hxWorld, eaveY, -hzWorld); // 0
    positions.push(hxWorld, eaveY, -hzWorld); //  1
    positions.push(hxWorld, eaveY, hzWorld); //   2
    positions.push(-hxWorld, eaveY, hzWorld); //  3
    positions.push(0, ridgeY, -hzWorld); //       4: ridge -Z end
    positions.push(0, ridgeY, hzWorld); //        5: ridge +Z end
    indices.push(1, 2, 5, 1, 5, 4); // +X slope
    indices.push(3, 0, 4, 3, 4, 5); // -X slope
    indices.push(0, 1, 4); // -Z end
    indices.push(2, 3, 5); // +Z end
  }
  const geom = new THREE.BufferGeometry();
  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geom.setIndex(indices);
  geom.computeVertexNormals();
  return new THREE.Mesh(geom, material);
}

/**
 * KRN-14 — hipped roof for a dormer. Ridge centred along the longer axis
 * but shorter than the eave; four sloped faces (two trapezoids + two
 * triangles).
 */
export function buildHippedDormerRoof(
  widthM: number,
  depthM: number,
  roofThickM: number,
  ridgeHeightM: number,
  ridgeAlongX: boolean,
  material: THREE.Material,
): THREE.Mesh {
  const longAlongWorldX = ridgeAlongX ? widthM >= depthM : depthM >= widthM;
  const hxWorld = ridgeAlongX ? widthM / 2 : depthM / 2;
  const hzWorld = ridgeAlongX ? depthM / 2 : widthM / 2;
  const eaveY = roofThickM;
  const ridgeY = eaveY + ridgeHeightM;
  const longHalf = longAlongWorldX ? hxWorld : hzWorld;
  const ridgeHalf = Math.max(0.05, longHalf * 0.5); // ridge spans 50% of long axis

  const positions: number[] = [];
  const indices: number[] = [];
  if (longAlongWorldX) {
    // Eaves
    positions.push(-hxWorld, eaveY, -hzWorld); // 0
    positions.push(hxWorld, eaveY, -hzWorld); //  1
    positions.push(hxWorld, eaveY, hzWorld); //   2
    positions.push(-hxWorld, eaveY, hzWorld); //  3
    // Ridge endpoints (centred on z=0)
    positions.push(-ridgeHalf, ridgeY, 0); //     4
    positions.push(ridgeHalf, ridgeY, 0); //      5
    // -Z trapezoid (verts 0,1,5,4)
    indices.push(0, 1, 5, 0, 5, 4);
    // +Z trapezoid (verts 2,3,4,5)
    indices.push(2, 3, 4, 2, 4, 5);
    // -X triangle (verts 3,0,4)
    indices.push(3, 0, 4);
    // +X triangle (verts 1,2,5)
    indices.push(1, 2, 5);
  } else {
    positions.push(-hxWorld, eaveY, -hzWorld); // 0
    positions.push(hxWorld, eaveY, -hzWorld); //  1
    positions.push(hxWorld, eaveY, hzWorld); //   2
    positions.push(-hxWorld, eaveY, hzWorld); //  3
    positions.push(0, ridgeY, -ridgeHalf); //     4
    positions.push(0, ridgeY, ridgeHalf); //      5
    // +X trapezoid (verts 1,2,5,4)
    indices.push(1, 2, 5, 1, 5, 4);
    // -X trapezoid (verts 3,0,4,5)
    indices.push(3, 0, 4, 3, 4, 5);
    // -Z triangle (verts 0,1,4)
    indices.push(0, 1, 4);
    // +Z triangle (verts 2,3,5)
    indices.push(2, 3, 5);
  }
  const geom = new THREE.BufferGeometry();
  geom.setAttribute('position', new THREE.Float32BufferAttribute(positions, 3));
  geom.setIndex(indices);
  geom.computeVertexNormals();
  return new THREE.Mesh(geom, material);
}

