1	import * as THREE from 'three';
2	
3	import type { Element } from '@bim-ai/core';
4	
5	import { getPlanPalette } from './symbology';
6	
7	type StairElem = Extract<Element, { kind: 'stair' }>;
8	type Vec2Mm = { xMm: number; yMm: number };
9	
10	const PLAN_Y_FLOOR = 0;
11	
12	/**
13	 * Pure geometry: vertices of one winder-tread wedge in plan (mm).
14	 *
15	 * The wedge is bounded by the inner and outer radii of a spiral / winder run
16	 * over the angular sweep [theta0, theta1] (radians, ccw from +x). Returned
17	 * polyline is closed (first == last) and ordered ccw when theta1 > theta0.
18	 *
19	 * For a winder section of an l_shape/u_shape stair, the caller passes the
20	 * pivot at the inner corner and computes (innerR, outerR, theta0, theta1)
21	 * from the two adjacent run bearings.
22	 */
23	export function winderWedgePoints(
24	  center: Vec2Mm,
25	  innerR: number,
26	  outerR: number,
27	  theta0: number,
28	  theta1: number,
29	  arcSegments = 8,
30	): Vec2Mm[] {
31	  if (innerR < 0) throw new Error('winderWedgePoints: innerR must be ≥ 0');
32	  if (outerR <= innerR) throw new Error('winderWedgePoints: outerR must exceed innerR');
33	
34	  const pts: Vec2Mm[] = [];
35	  for (let s = 0; s <= arcSegments; s++) {
36	    const t = theta0 + (theta1 - theta0) * (s / arcSegments);
37	    pts.push({
38	      xMm: center.xMm + innerR * Math.cos(t),
39	      yMm: center.yMm + innerR * Math.sin(t),
40	    });
41	  }
42	  for (let s = arcSegments; s >= 0; s--) {
43	    const t = theta0 + (theta1 - theta0) * (s / arcSegments);
44	    pts.push({
45	      xMm: center.xMm + outerR * Math.cos(t),
46	      yMm: center.yMm + outerR * Math.sin(t),
47	    });
48	  }
49	  pts.push({ ...pts[0] });
50	  return pts;
51	}
52	
53	/**
54	 * Plan-symbology renderer for spiral stairs (winder treads). Returns a Group
55	 * of fanned wedge outlines plus an up-arrow at the bottom of the run. Caller
56	 * positions the group at PLAN_Y + small offset.
57	 */
58	export function spiralStairPlanGroup(
59	  stair: StairElem,
60	  yOffset: number = PLAN_Y_FLOOR + 0.018,
61	): THREE.Group | null {
62	  if (
63	    stair.shape !== 'spiral' ||
64	    stair.centerMm == null ||
65	    stair.innerRadiusMm == null ||
66	    stair.outerRadiusMm == null ||
67	    stair.totalRotationDeg == null
68	  ) {
69	    return null;
70	  }
71	  const riserCount = Math.max(1, stair.runs?.[0]?.riserCount ?? 12);
72	  const stepRad = THREE.MathUtils.degToRad(stair.totalRotationDeg) / riserCount;
73	  const palette = getPlanPalette();
74	
75	  const g = new THREE.Group();
76	  const treadMat = new THREE.LineBasicMaterial({
77	    color: palette.hairlineStrong,
78	    transparent: true,
79	    opacity: 0.7,
80	  });
81	  const outlineMat = new THREE.LineBasicMaterial({
82	    color: palette.dimAlt,
83	    transparent: true,
84	    opacity: 0.92,
85	  });
86	
87	  for (let i = 0; i < riserCount; i++) {
88	    const theta0 = stepRad * i;
89	    const theta1 = stepRad * (i + 1);
90	    const pts = winderWedgePoints(
91	      stair.centerMm,
92	      stair.innerRadiusMm,
93	      stair.outerRadiusMm,
94	      theta0,
95	      theta1,
96	    );
97	    const v3 = pts.map((p) => new THREE.Vector3(p.xMm / 1000, yOffset, p.yMm / 1000));
98	    const mat = i === riserCount - 1 ? outlineMat : treadMat;
99	    g.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(v3), mat));
100	  }
101	
102	  // Up-arrow at the bottom of the run, pointing along the first tread's
103	  // angular direction at the midline radius.
104	  const midR = (stair.innerRadiusMm + stair.outerRadiusMm) * 0.5;
105	  const tail = {
106	    x: stair.centerMm.xMm + midR * Math.cos(0),
107	    z: stair.centerMm.yMm + midR * Math.sin(0),
108	  };
