      hostRoofId: 'r1',
      positionOnRoof: { alongRidgeMm: -2000, acrossRidgeMm: 1000 },
      widthMm: 2400,
      wallHeightMm: 2400,
      depthMm: 2000,
      dormerRoofKind: 'flat',
      wallMaterialKey: 'white_render',
    };
